	reverse(t.begin(),t.end());
	vector<array<int,3>> dp(2);
	constexpr int inf=INT_MAX/2;
	dp[1]={inf,0,inf};
	for(int i=0;i<n;i++){
		auto &cur = dp[i&1],&pre = dp[~i & 1];
		for(int c=0;c<3;c++){
			cur[c]=inf;
			int terget= t[i]-'0'+(c-1)*10;
			for(int p=0;p< 3;p++){
				int from = s[i]-'0'+(p-1);
				cur[c] = min(cur[c],pre[p]+abs(terget-from));
			}
		}

	}
	cout<<*min_element(dp[~n&1].begin(),dp[~n&1].end());
	return 0;
}
